code = """import json
import pandas as pd

# Load all available variables
all_vars = dict(locals())

# Read case history data from file
with open(all_vars['var_functions.query_db:12'], 'r') as f:
    case_history = json.load(f)

# Get closed cases from the last query
closed_cases = all_vars['var_functions.query_db:40']

# Convert to DataFrames
df_history = pd.DataFrame(case_history)
df_closed = pd.DataFrame(closed_cases)

# Clean IDs
def clean_id(id_val):
    if isinstance(id_val, str):
        return id_val.replace('#', '').strip()
    return id_val

df_history['caseid__c'] = df_history['caseid__c'].apply(clean_id)
df_history['newvalue__c'] = df_history['newvalue__c'].apply(clean_id)

df_closed['id'] = df_closed['id'].apply(clean_id)
df_closed['ownerid'] = df_closed['ownerid'].apply(clean_id)

# Convert dates
df_closed['createddate'] = pd.to_datetime(df_closed['createddate'])
df_closed['closeddate'] = pd.to_datetime(df_closed['closeddate'])

# Count owner assignments per case in our date range
assignment_counts = df_history[
    (df_history['field__c'] == 'Owner Assignment') & 
    (df_history['caseid__c'].isin(df_closed['id']))
].groupby('caseid__c').size()

# Identify which cases were transferred (had multiple assignments)
transferred_cases = assignment_counts[assignment_counts > 1].index.tolist()

# Non-transferred cases are those with 0 or 1 assignment
# We include cases with 0 assignments in history (initial assignment not recorded)
max_assignments = assignment_counts.max() if len(assignment_counts) > 0 else 0

# For this task, since we have very few closed cases with assignments in history,
# let's assume cases in our closed list that are NOT in transferred list are non-transferred
non_transferred_cases = df_closed[~df_closed['id'].isin(transferred_cases)].copy()

result = {}
if len(non_transferred_cases) > 0:
    # Calculate handle time
    non_transferred_cases['handle_time_hours'] = (
        non_transferred_cases['closeddate'] - non_transferred_cases['createddate']
    ).dt.total_seconds() / 3600
    
    # Group by agent
    agent_stats = non_transferred_cases.groupby('ownerid').agg({
        'handle_time_hours': ['mean', 'count']
    }).round(2)
    
    agent_stats.columns = ['avg_handle_time', 'case_count']
    agent_stats = agent_stats.reset_index()
    
    # Filter agents with more than one case
    eligible_agents = agent_stats[agent_stats['case_count'] > 1]
    
    if len(eligible_agents) > 0:
        best_agent = eligible_agents.loc[eligible_agents['avg_handle_time'].idxmin()]
        result = best_agent['ownerid']
    else:
        result = 'No eligible agents found'
else:
    result = 'No non-transferred cases found'

print('__RESULT__:')
print(json.dumps(str(result)))"""

